"use strict";parserFactory.register("biquge.tw",()=>new BiqugetwParser);class BiqugetwParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("a.chapterlist").href,t=(await HttpClient.wrapFetch(r)).responseXML.querySelector("div.booklist ul");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector("#chaptercontent")}extractTitleImpl(e){return e.querySelector(".book h1")}extractAuthor(e){let r=e.querySelector(".book .right h2 a");return r?.textContent??super.extractAuthor(e)}extractLanguage(){return"zh"}findChapterTitle(e){return e.querySelector(".book h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".cover")}async fetchChapter(e){return this.walkPagesOfChapter(e,this.moreChapterTextUrl)}moreChapterTextUrl(e){return[...e.querySelectorAll("a#next_url")].filter(e=>e.href.includes("_")).map(e=>e.href).pop()??null}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.intro")]}}